1	import { useCallback, useEffect, useMemo, useState } from 'react';
2	import {
3	  ActivityIndicator,
4	  KeyboardAvoidingView,
5	  Platform as RNPlatform,
6	  SafeAreaView,
7	  ScrollView,
8	  StyleSheet,
9	  Text,
10	  TextInput,
11	  View,
12	} from 'react-native';
13	import { Gesture, GestureDetector } from 'react-native-gesture-handler';
14	import Animated, {
15	  runOnJS,
16	  useAnimatedStyle,
17	  useSharedValue,
18	  withSpring,
19	  type WithSpringConfig,
20	} from 'react-native-reanimated';
21	import { BottomSheet } from '@/components/primitives/BottomSheet';
22	import { ButtonPrimary, ButtonSecondary } from '@/components/primitives/Button';
23	import { useToast } from '@/components/primitives/Toast';
24	import { SPRING_SNAPPY, withReducedMotion } from '@/design/motion';
25	import { colors, radii, shadows, spacing } from '@/design/tokens';
26	import { textStyles } from '@/design/typography';
27	import { useReducedMotion } from '@/design/useReducedMotion';
28	import { useAuth } from '@/lib/auth';
29	import { getCachedToken } from '@/lib/storage';
30	import { supabase } from '@/lib/supabase';
31	import { formatRelativeTime, formatRetryAfter } from '@/lib/time';
32	import type { Database } from '@/types/supabase';
33	
34	// US-035 — creator profile. Shows TikTok + Instagram handles with their
35	// denormalized follower counts / avg views, a "Stale" chip when the latest
36	// metric_snapshot was flipped to status='stale' by the hourly cron, and an
37	// Add / Unlink flow wired to the manage-social-link edge function.
38	//
39	// Spec gap: the story AC says "Stale chip appears when metrics_stale_at is
40	// non-null", but there is no metrics_stale_at column on creator_profiles
41	// (see us_004 + the us_011 cron which flips metric_snapshots.status='stale'
42	// instead). The chip is therefore derived from
43	// metric_snapshots WHERE is_latest = true AND status = 'stale', which is
44	// the signal the cron actually produces per docs/tech-architecture.md §16.
45	//
46	// US-036 extends this screen with per-platform pull-to-refresh that calls
47	// the metrics-refresh edge function. On 429 we surface the server's
48	// retry_after_sec as "Try again in Xh Ym". On success we optimistically
49	// bump `last_refreshed_at` locally and subscribe to metric_snapshots
50	// inserts so webhook-driven denorm updates roll in without a reload.
51	
52	type SocialPlatform = Database['public']['Enums']['platform'];
53	type SocialLink = Database['public']['Tables']['social_links']['Row'];
54	type CreatorProfileRow = Database['public']['Tables']['creator_profiles']['Row'];
55	type MetricStatus = Database['public']['Enums']['metric_status'];
56	type SnapshotEntry = { status: MetricStatus; fetched_at: string };
57	
58	const HANDLE_RE = /^[a-zA-Z0-9_.]{1,30}$/;
59	const PLATFORMS: readonly SocialPlatform[] = ['tiktok', 'instagram'];
60	const REFRESH_THRESHOLD = 64;
61	const REFRESH_MAX_DRAG = 140;
62	
63	export default function CreatorProfile() {
64	  const { user, signOut } = useAuth();
65	  const { show: showToast } = useToast();
66	
67	  const [profile, setProfile] = useState<CreatorProfileRow | null>(null);
68	  const [links, setLinks] = useState<SocialLink[]>([]);
69	  const [snapshotByLink, setSnapshotByLink] = useState<Map<string, SnapshotEntry>>(new Map());
70	  const [loading, setLoading] = useState(true);
71	  const [pendingAction, setPendingAction] = useState<string | null>(null);
72	  const [sheetPlatform, setSheetPlatform] = useState<SocialPlatform | null>(null);
73	  const [refreshingLinkId, setRefreshingLinkId] = useState<string | null>(null);
74	
75	  const load = useCallback(async () => {
76	    if (!user) return;
77	    setLoading(true);
78	    try {
79	      const [profileRes, linksRes] = await Promise.all([
80	        supabase
81	          .from('creator_profiles')
82	          .select('*')
83	          .eq('user_id', user.id)
84	          .maybeSingle(),
85	        supabase
86	          .from('social_links')
87	          .select('*')
88	          .eq('user_id', user.id)
89	          .neq('status', 'unlinked'),
90	      ]);
91	      if (profileRes.error) throw profileRes.error;
92	      if (linksRes.error) throw linksRes.error;
93	      const linkRows = linksRes.data ?? [];
94	      const linkIds = linkRows.map((l) => l.id);
95	      const snapshotMap = new Map<string, SnapshotEntry>();
96	      if (linkIds.length > 0) {
97	        const snapsRes = await supabase
98	          .from('metric_snapshots')
99	          .select('social_link_id, status, fetched_at')
100	          .eq('is_latest', true)
101	          .in('social_link_id', linkIds);
102	        if (snapsRes.error) throw snapsRes.error;
103	        for (const row of snapsRes.data ?? []) {
104	          snapshotMap.set(row.social_link_id, {
105	            status: row.status,
106	            fetched_at: row.fetched_at,
107	          });
108	        }
109	      }
110	      setProfile(profileRes.data ?? null);
111	      setLinks(linkRows);
112	      setSnapshotByLink(snapshotMap);
113	    } catch (err) {
114	      console.error('Profile load failed', err);
115	      showToast({ message: 'Could not load profile.', variant: 'error' });
116	    } finally {
117	      setLoading(false);
118	    }
119	  }, [user, showToast]);
120	
121	  useEffect(() => {
122	    void load();
123	  }, [load]);
124	
125	  // Realtime: when the apify-webhook (or cron) inserts a fresh/stale
126	  // metric_snapshots row for one of this creator's linked handles, the
127	  // denorm trigger also updates creator_profiles — reload everything so
128	  // the "Last refreshed" stamp + the denorm metric counts roll forward.
129	  // Keyed on a stable string of sorted link ids to avoid resubscribing on
130	  // every setLinks reference flip.
131	  const linkIdKey = useMemo(
132	    () => links.map((l) => l.id).sort().join(','),
133	    [links],
134	  );
135	
136	  useEffect(() => {
137	    if (!user || linkIdKey === '') return;
138	    const ids = linkIdKey.split(',');
139	    const token = getCachedToken();
140	    if (!token) return;
141	    let cancelled = false;
142	    let activeChannel: ReturnType<typeof supabase.channel> | null = null;
143	    // Realtime runs over a websocket — the marketifyFetch Authorization
144	    // wrapper in src/lib/supabase.ts only covers HTTP, so inject the JWT
145	    // into the Realtime client explicitly before subscribing. RLS then
146	    // applies metric_snapshots_self_read (us_035) to the stream.
147	    void supabase.realtime.setAuth(token).then(() => {
148	      if (cancelled) return;
149	      activeChannel = supabase
150	        .channel(`creator-metrics-${user.id}`)
151	        .on(
152	          'postgres_changes',
153	          {
154	            event: 'INSERT',
155	            schema: 'public',
156	            table: 'metric_snapshots',
157	            filter: `social_link_id=in.(${ids.join(',')})`,
158	          },
159	          (payload) => {
160	            const row = payload.new as { is_latest?: boolean; status?: MetricStatus };
161	            if (row.is_latest === true && (row.status === 'fresh' || row.status === 'stale')) {
162	              void load();
163	            }
164	          },
165	        )
166	        .subscribe();
167	    });
168	    return () => {
169	      cancelled = true;
170	      if (activeChannel) void supabase.removeChannel(activeChannel);
171	    };
172	  }, [user, linkIdKey, load]);
173	
174	  const onRefresh = useCallback(
175	    async (link: SocialLink) => {
176	      if (refreshingLinkId) return;
177	      setRefreshingLinkId(link.id);
178	      try {
179	        const { data, error } = await supabase.functions.invoke<{
180	          status?: 'queued' | 'already_fresh';
181	        }>('metrics-refresh', { body: { social_link_id: link.id } });
182	        if (error) {
183	          const ctx = (error as { context?: unknown }).context;
184	          if (
185	            ctx &&
186	            typeof ctx === 'object' &&
187	            'status' in ctx &&
188	            typeof (ctx as { json?: unknown }).json === 'function'
189	          ) {
190	            const res = ctx as Response;
191	            let body: { error?: string; retry_after_sec?: number } = {};
192	            try {
193	              body = (await res.json()) as { error?: string; retry_after_sec?: number };
194	            } catch {
195	              // non-JSON body — fall through to generic toast
196	            }
197	            if (res.status === 429 && typeof body.retry_after_sec === 'number') {
198	              showToast({
199	                message: `Try again in ${formatRetryAfter(body.retry_after_sec)}`,
200	                variant: 'error',
201	              });
202	              return;
203	            }
204	            if (res.status === 422 && body.error === 'LINK_UNLINKED') {
205	              showToast({ message: 'Handle is no longer linked.', variant: 'error' });
206	              return;
207	            }
208	          }
209	          showToast({ message: 'Could not refresh metrics.', variant: 'error' });
210	          return;
211	        }
212	        // Optimistic stamp so "Last refreshed" reads "just now" until the
213	        // Apify webhook lands and realtime triggers a reload. For the
214	        // already_fresh path the stamp is effectively a no-op (the row
215	        // was recently refreshed anyway) — still safe to bump.
216	        setSnapshotByLink((prev) => {
217	          const next = new Map(prev);
218	          const existing = next.get(link.id);
219	          next.set(link.id, {
220	            status: existing?.status ?? 'fresh',
221	            fetched_at: new Date().toISOString(),
222	          });
223	          return next;
224	        });
225	        if (data?.status === 'queued') {
226	          showToast({ message: 'Refreshing metrics…', variant: 'success' });
227	        }
228	      } finally {
229	        setRefreshingLinkId(null);
230	      }
231	    },
232	    [refreshingLinkId, showToast],
233	  );
234	
235	  const sections = useMemo(() => {
236	    return PLATFORMS.map((platform) => {
237	      const link = links.find((l) => l.platform === platform) ?? null;
238	      const snap = link ? snapshotByLink.get(link.id) ?? null : null;
239	      const isStale = snap?.status === 'stale';
240	      const lastRefreshedAt = snap?.fetched_at ?? null;
241	      return { platform, link, isStale, lastRefreshedAt };
242	    });
243	  }, [links, snapshotByLink]);
244	
245	  const onAdd = useCallback(
246	    async (platform: SocialPlatform, rawHandle: string) => {
247	      const handle = rawHandle.trim().replace(/^@+/, '').trim();
248	      if (!HANDLE_RE.test(handle)) {
249	        showToast({
250	          message: 'Handle must be letters, numbers, underscores, or dots.',
251	          variant: 'error',
252	        });
253	        return;
254	      }
255	      setPendingAction(`add:${platform}`);
256	      try {
257	        const { data, error } = await supabase.functions.invoke<{ social_link_id: string }>(
258	          'manage-social-link',
259	          { body: { action: 'add', platform, handle } },
260	        );
261	        if (error) {
262	          const ctx = (error as { context?: unknown }).context;
263	          if (
264	            ctx &&
265	            typeof ctx === 'object' &&
266	            'status' in ctx &&
267	            typeof (ctx as { json?: unknown }).json === 'function'
268	          ) {
269	            const res = ctx as Response;
270	            let body: { error?: string } = {};
271	            try {
272	              body = (await res.json()) as { error?: string };
273	            } catch {
274	              // non-JSON body — fall through to generic toast
275	            }
276	            if (res.status === 409 && body.error === 'ALREADY_LINKED') {
277	              showToast({
278	                message: `You already have a ${platformLabel(platform)} handle linked.`,
279	                variant: 'error',
280	              });
281	              return;
282	            }
283	            if (res.status === 409 && body.error === 'HANDLE_TAKEN') {
284	              showToast({
285	                message: 'That handle is already linked to another account.',
286	                variant: 'error',
287	              });
288	              return;
289	            }
290	          }
291	          showToast({ message: 'Could not add handle.', variant: 'error' });
292	          return;
293	        }
294	        if (!data?.social_link_id) {
295	          showToast({ message: 'Could not add handle.', variant: 'error' });
296	          return;
297	        }
298	        setSheetPlatform(null);
299	        showToast({
300	          message: `${platformLabel(platform)} handle added.`,
301	          variant: 'success',
302	        });
303	        await load();
304	      } finally {
305	        setPendingAction(null);
306	      }
307	    },
308	    [showToast, load],
309	  );
310	
311	  const onUnlink = useCallback(
312	    async (link: SocialLink) => {
313	      setPendingAction(`unlink:${link.id}`);
314	      try {
315	        const { error } = await supabase.functions.invoke('manage-social-link', {
316	          body: { action: 'unlink', social_link_id: link.id },
317	        });
318	        if (error) {
319	          showToast({ message: 'Could not unlink handle.', variant: 'error' });
320	          return;
321	        }
322	        showToast({
323	          message: `${platformLabel(link.platform)} handle unlinked.`,
324	          variant: 'success',
325	        });
326	        await load();
327	      } finally {
328	        setPendingAction(null);
329	      }
330	    },
331	    [showToast, load],
332	  );
333	
334	  return (
335	    <SafeAreaView style={styles.container}>
336	      <ScrollView contentContainerStyle={styles.scrollContent}>
337	        <View style={styles.header}>
338	          <Text style={[textStyles.display, { color: colors.ink }]}>Profile</Text>
339	          {user ? (
340	            <Text style={[textStyles.mono, styles.usernameRow]}>@{user.username}</Text>
341	          ) : null}
342	        </View>
343	
344	        {loading && profile === null ? (
345	          <View style={styles.loadingBlock}>
346	            <ActivityIndicator color={colors.ink} />
347	          </View>
348	        ) : (
349	          <View style={styles.sections}>
350	            {sections.map(({ platform, link, isStale, lastRefreshedAt }) => (
351	              <PlatformCard
352	                key={platform}
353	                platform={platform}
354	                link={link}
355	                profile={profile}
356	                isStale={isStale}
357	                lastRefreshedAt={lastRefreshedAt}
358	                pendingAction={pendingAction}
359	                refreshing={link !== null && refreshingLinkId === link.id}
360	                onOpenAdd={() => setSheetPlatform(platform)}
361	                onUnlink={onUnlink}
362	                onRefresh={onRefresh}
363	              />
364	            ))}
365	          </View>
366	        )}
367	
368	        <View style={styles.signOutWrap}>
369	          <ButtonSecondary
370	            label="Sign out"
371	            onPress={signOut}
372	            accessibilityLabel="Sign out"
373	            testID="creator-signout"
374	          />
375	        </View>
376	      </ScrollView>
377	
378	      <AddHandleSheet
379	        platform={sheetPlatform}
380	        onDismiss={() => setSheetPlatform(null)}
381	        onSubmit={onAdd}
382	        submitting={sheetPlatform !== null && pendingAction === `add:${sheetPlatform}`}
383	      />
384	    </SafeAreaView>
385	  );
386	}
