388	type PlatformCardProps = {
389	  platform: SocialPlatform;
390	  link: SocialLink | null;
391	  profile: CreatorProfileRow | null;
392	  isStale: boolean;
393	  lastRefreshedAt: string | null;
394	  pendingAction: string | null;
395	  refreshing: boolean;
396	  onOpenAdd: () => void;
397	  onUnlink: (link: SocialLink) => void;
398	  onRefresh: (link: SocialLink) => void;
399	};
400	
401	function PlatformCard({
402	  platform,
403	  link,
404	  profile,
405	  isStale,
406	  lastRefreshedAt,
407	  pendingAction,
408	  refreshing,
409	  onOpenAdd,
410	  onUnlink,
411	  onRefresh,
412	}: PlatformCardProps) {
413	  const { follower, avgViews } = extractMetrics(platform, profile);
414	  const lastRefreshedLabel = lastRefreshedAt
415	    ? formatRelativeTime(new Date(lastRefreshedAt))
416	    : 'Never';
417	  const unlinkLoading = link ? pendingAction === `unlink:${link.id}` : false;
418	
419	  const cardBody = (
420	    <>
421	      <View style={styles.cardHeader}>
422	        <Text style={[textStyles.h2, { color: colors.ink }]}>{platformLabel(platform)}</Text>
423	        {isStale && link ? <StaleChip /> : null}
424	      </View>
425	
426	      {link ? (
427	        <>
428	          <Text style={[textStyles.mono, styles.handleRow]}>@{link.handle}</Text>
429	          <View style={styles.metricsRow}>
430	            <Metric label="Followers" value={formatCount(follower)} />
431	            <Metric label="Avg views" value={formatCount(avgViews)} />
432	          </View>
433	          <Text style={[textStyles.caption, styles.lastRefreshed]}>
434	            Last refreshed {lastRefreshedLabel}
435	          </Text>
436	          <View style={styles.cardAction}>
437	            <ButtonSecondary
438	              label="Unlink handle"
439	              onPress={() => onUnlink(link)}
440	              loading={unlinkLoading}
441	              disabled={unlinkLoading}
442	              accessibilityLabel={`Unlink ${platformLabel(platform)} handle`}
443	              testID={`unlink-${platform}`}
444	            />
445	          </View>
446	        </>
447	      ) : (
448	        <>
449	          <Text style={[textStyles.body, styles.emptyRow]}>
450	            No {platformLabel(platform)} handle linked.
451	          </Text>
452	          <View style={styles.cardAction}>
453	            <ButtonPrimary
454	              label={`Add ${platformLabel(platform)} handle`}
455	              onPress={onOpenAdd}
456	              accessibilityLabel={`Add ${platformLabel(platform)} handle`}
457	              testID={`add-${platform}`}
458	            />
459	          </View>
460	        </>
461	      )}
462	    </>
463	  );
464	
465	  if (!link) {
466	    return <View style={styles.card}>{cardBody}</View>;
467	  }
468	
469	  return (
470	    <RefreshablePlatformCard
471	      link={link}
472	      refreshing={refreshing}
473	      onRefresh={onRefresh}
474	      testID={`refresh-${platform}`}
475	    >
476	      {cardBody}
477	    </RefreshablePlatformCard>
478	  );
479	}
