481	function RefreshablePlatformCard({
482	  link,
483	  refreshing,
484	  onRefresh,
485	  testID,
486	  children,
487	}: {
488	  link: SocialLink;
489	  refreshing: boolean;
490	  onRefresh: (link: SocialLink) => void;
491	  testID?: string;
492	  children: React.ReactNode;
493	}) {
494	  const reduced = useReducedMotion();
495	  const offset = useSharedValue(0);
496	  const locked = useSharedValue(false);
497	
498	  useEffect(() => {
499	    locked.value = refreshing;
500	  }, [refreshing, locked]);
501	
502	  const triggerRefresh = useCallback(() => {
503	    onRefresh(link);
504	  }, [onRefresh, link]);
505	
506	  const pan = useMemo(
507	    () =>
508	      Gesture.Pan()
509	        .activateAfterLongPress(120)
510	        .failOffsetX([-20, 20])
511	        .onUpdate((e) => {
512	          if (locked.value) return;
513	          // Dampen past the threshold so the card resists further pull.
514	          const raw = Math.max(0, e.translationY);
515	          const damped =
516	            raw <= REFRESH_THRESHOLD
517	              ? raw
518	              : REFRESH_THRESHOLD + (raw - REFRESH_THRESHOLD) * 0.35;
519	          offset.value = Math.min(damped, REFRESH_MAX_DRAG);
520	        })
521	        .onEnd(() => {
522	          if (locked.value) return;
523	          if (offset.value >= REFRESH_THRESHOLD) {
524	            runOnJS(triggerRefresh)();
525	          }
526	          offset.value = withSpring(
527	            0,
528	            withReducedMotion<WithSpringConfig>(SPRING_SNAPPY, reduced),
529	          );
530	        })
531	        .onFinalize(() => {
532	          if (locked.value) return;
533	          offset.value = withSpring(
534	            0,
535	            withReducedMotion<WithSpringConfig>(SPRING_SNAPPY, reduced),
536	          );
537	        }),
538	    [reduced, offset, locked, triggerRefresh],
539	  );
540	
541	  const cardStyle = useAnimatedStyle(() => ({
542	    transform: [{ translateY: offset.value }],
543	  }));
544	
545	  const spinnerStyle = useAnimatedStyle(() => {
546	    const progress = Math.min(1, offset.value / REFRESH_THRESHOLD);
547	    return {
548	      opacity: progress,
549	      transform: [{ scale: 0.9 + progress * 0.1 }],
550	    };
551	  });
552	
553	  return (
554	    <View style={styles.refreshSlot} testID={testID}>
555	      <Animated.View
556	        pointerEvents="none"
557	        style={[styles.spinnerTrack, spinnerStyle]}
558	        accessible={false}
559	        importantForAccessibility="no"
560	      >
561	        <ActivityIndicator color={colors.ink} />
562	      </Animated.View>
563	      {refreshing ? (
564	        <View
565	          style={styles.spinnerLocked}
566	          accessible
567	          accessibilityRole="progressbar"
568	          accessibilityLabel="Refreshing metrics"
569	          testID={`${testID}-spinner`}
570	        >
571	          <ActivityIndicator color={colors.ink} />
572	        </View>
573	      ) : null}
574	      <GestureDetector gesture={pan}>
575	        <Animated.View style={[styles.card, cardStyle]}>{children}</Animated.View>
576	      </GestureDetector>
577	    </View>
578	  );
579	}
580	
581	function Metric({ label, value }: { label: string; value: string }) {
582	  return (
583	    <View style={styles.metric}>
584	      <Text style={[textStyles.caption, { color: colors.ink70 }]}>{label}</Text>
585	      <Text style={[textStyles.h1, { color: colors.ink }]}>{value}</Text>
586	    </View>
587	  );
588	}
